#!/bin/bash
export OPENBLAS_NUM_THREADS=1
cargo run --release '{"structured_operator_type": "BemppRsLaplaceOperator", "precision": "Double"}' '{"id_tols": [0.01, 0.001, 0.0001, 1e-06, 1e-08], "dim_args": [{"RefinementLevelAndDepth": [5, 2]}], "geometry_type": "SphereSurface"}' '{"oversampling": 8, "oversampling_diag_blocks": 16, "initial_num_samples": 20, "null_method": "Projection", "near_block_extraction_method": "LuLstSq", "diag_block_extraction_method": "LuLstSq", "lu_pivot_method": "Lu", "diag_pivot_method": "Lu", "tol_null": 1e-10, "tol_id": 0.01, "tol_ext_near": 1e-10, "tol_diag_ext": 1e-16, "min_rank": 4, "min_level": 1, "hermitian": true, "rank_picking": "Min"}' '{"solve": {"True": 1e-05}, "plot": true, "dense_errors": false, "results_output": "All"}'
